/**
 * VenaPrismHook — CREATE2 Address Miner
 *
 * Prism model: afterSwap is a no-op (no return delta).
 * Required hook flag:
 *   AFTER_SWAP_FLAG = bit 6 (0x0040)
 *
 * HOW TO USE:
 *   1. Compile VenaPrismHook.sol + VenaMirror.sol in Remix (EVM: cancun, OZ 5.x).
 *   2. Copy BYTECODE "object" from VenaPrismHook compilation details.
 *   3. Paste into RAW_BYTECODE below.
 *   4. Fill constructor addresses (4 args).
 *   5. Run: node prism-mine-hook.js
 *
 * Requirements: npm install ethers (v6)
 */

const fs = require("fs");
const path = require("path");

const { keccak256, getCreate2Address, toBeHex, zeroPadValue, getAddress } = require("ethers");

// ─── FILL IN ─────────────────────────────────────────────────────────────────

const DEPLOYER = "0x3b8C25CA63f901792570B1bbaDfF83369d25fF4c";

// Paste VenaPrismHook bytecode ONLY (no constructor args)
const RAW_BYTECODE = "";

// VenaPrismHook constructor: (poolManager, owner, posm, permit2)
const POOL_MANAGER  = getAddress("0x498581fF718922c3f8e6A244956aF099B2652b2b");
const INITIAL_OWNER = getAddress("0x3b8C25CA63f901792570B1bbaDfF83369d25fF4c");
const POSM          = getAddress("0x7C5f5A4bBd8fD63184577525326123B519429bDc");
const PERMIT2       = getAddress("0x000000000022D473030F116dDEE9F6B43aC78BA3");

const FACTORY = "0xDe63f3bd3C402688132BfE73C0C9F3Fe19EbF131";

// ─── BUILD INITCODE ──────────────────────────────────────────────────────────

if (RAW_BYTECODE === "" || RAW_BYTECODE.length < 20) {
    console.error("\nERROR: Paste VenaPrismHook bytecode from Remix into RAW_BYTECODE.\n");
    process.exit(1);
}

const bytecode    = RAW_BYTECODE.startsWith("0x") ? RAW_BYTECODE : "0x" + RAW_BYTECODE;

// Manual encode avoids ethers checksum errors on Permit2 (0x0000...22D4...)
function encodeAddr(addr) {
    return zeroPadValue(addr.toLowerCase(), 32).slice(2);
}
const encodedArgs = "0x" + [
    POOL_MANAGER,
    INITIAL_OWNER,
    POSM,
    PERMIT2,
].map(encodeAddr).join("");
const INITCODE      = bytecode + encodedArgs.slice(2);
const INITCODE_HASH = keccak256(INITCODE);

// ─── MINING ──────────────────────────────────────────────────────────────────

const FLAG_MASK = BigInt("0x3FFF");
const TARGET    = BigInt("0x0040"); // afterSwap only — no return delta

console.log("Mining VenaPrismHook — target flag: 0x0040");
console.log("Deployer:", DEPLOYER);
console.log("Factory:", FACTORY);
console.log("");

let found = false;

for (let salt = 0n; salt < 10_000_000n; salt++) {
    const saltHex = zeroPadValue(toBeHex(salt), 32);
    const addr    = getCreate2Address(FACTORY, saltHex, INITCODE_HASH);
    const addrBig = BigInt(addr);

    if ((addrBig & FLAG_MASK) === TARGET) {
        const initcodePath = path.join(__dirname, "prism-hook-initcode.txt");
        fs.writeFileSync(initcodePath, INITCODE + "\n");

        console.log("✓ Found valid Prism hook address!\n");
        console.log("  Hook address :", addr);
        console.log("  Salt (bytes32):", saltHex);
        console.log("  InitCode file:", initcodePath);
        console.log("");
        console.log("─── REMIX DEPLOY (use deploy(), NOT low-level calldata) ────────────");
        console.log("  1. Remix → open Create2Deploy.sol");
        console.log("  2. Environment: Injected Provider (MetaMask, Base)");
        console.log("  3. Deploy & Run → At Address:", FACTORY);
        console.log("  4. Expand Create2Deploy → function deploy");
        console.log("  5. salt (bytes32):", saltHex);
        console.log("  6. initCode (bytes): paste from", initcodePath);
        console.log("  7. Transact → deployed address must be:", addr);
        console.log("────────────────────────────────────────────────────────────────────");
        found = true;
        break;
    }

    if (salt % 100_000n === 0n) {
        process.stdout.write(`\r  Tried: ${salt.toLocaleString()}...`);
    }
}

if (!found) {
    console.log("\nNo valid address in 10M attempts. Check bytecode and addresses.");
}
